import { withDb } from "./db.mjs";

// JSONB schema: each entity gets a primary-key column + a doc JSONB column.
// This matches the postgres-jsonb storage pattern used by accounts.mjs, queries.mjs, etc.
const JSONB_TABLES = [
  { table: "accounts",          pk: "account_id" },
  { table: "orders",            pk: "order_id" },
  { table: "invoices",          pk: "invoice_id" },
  { table: "payments",          pk: "payment_id" },
  { table: "payment_methods",   pk: "payment_method_id" },
  { table: "credit_notes",      pk: "credit_note_id" },
  { table: "tax_records",       pk: "tax_record_id" },
  { table: "billing_cycles",    pk: "cycle_id" },
  { table: "products",          pk: "product_id" },
  { table: "product_categories",pk: "category_id" },
  { table: "product_inventory", pk: "inventory_id" },
  { table: "shipments",         pk: "shipment_id" },
  { table: "support_cases",     pk: "case_id" },
  { table: "compliance_reviews",pk: "review_id" },
  { table: "audit_trails",      pk: "audit_id" },
  { table: "data_processing_agreements", pk: "dpa_id" },
  { table: "consent_records",   pk: "consent_id" },
  { table: "account_contracts", pk: "contract_id" },
];

let schemaEnsured = false;

export async function ensureSchema(client) {
  if (schemaEnsured) return;
  for (const { table, pk } of JSONB_TABLES) {
    await client.query(
      `CREATE TABLE IF NOT EXISTS ${table} (${pk} TEXT PRIMARY KEY, doc JSONB NOT NULL)`
    );
  }
  schemaEnsured = true;
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

