export async function ensureSchema(client) {
  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc JSONB
    )
  `);
  // Add doc column if table was previously created without it
  await client.query(`ALTER TABLE accounts ADD COLUMN IF NOT EXISTS doc JSONB`).catch(() => {});

  await client.query(`
    CREATE TABLE IF NOT EXISTS orders (
      order_id TEXT PRIMARY KEY,
      account_id TEXT,
      doc JSONB
    )
  `);
  await client.query(`ALTER TABLE orders ADD COLUMN IF NOT EXISTS doc JSONB`).catch(() => {});
  await client.query(`ALTER TABLE orders ADD COLUMN IF NOT EXISTS account_id TEXT`).catch(() => {});

  await client.query(`
    CREATE TABLE IF NOT EXISTS invoices (
      invoice_id TEXT PRIMARY KEY,
      account_id TEXT,
      doc JSONB
    )
  `);
  await client.query(`ALTER TABLE invoices ADD COLUMN IF NOT EXISTS doc JSONB`).catch(() => {});
  await client.query(`ALTER TABLE invoices ADD COLUMN IF NOT EXISTS account_id TEXT`).catch(() => {});
}

export { PREFERRED_PAYMENT_METHODS };

